/**
 * Wraps rendered lines with vertical borders.
 * @param lines The already-rendered lines from your component.
 * @param theme The current theme object (required for coloring).
 * @param width The total terminal width available.
 */
export function withBorders(lines: string[], theme: any, width: number): string[] {
	const leftBorder = theme.fg("success", "│ ");
	const rightBorder = theme.fg("success", " │");

	// We assume lines were rendered for width - 4 to account for border widths + spaces
	const innerWidth = width - 4;

	return lines.map((line) => {
		const vw = visibleWidth(line);
		const padded = line + " ".repeat(Math.max(0, innerWidth - vw));
		return leftBorder + padded + rightBorder;
	});
